"use client";

import Link from "next/link";
import { usePathname } from "next/navigation";
import { motion } from "framer-motion";
import { ThemeToggle } from "./ThemeToggle";
import { Command } from "lucide-react";
import { useState, useEffect } from "react";
import { CommandMenu } from "./CommandMenu";

const links = [
    { name: "Home", path: "/" },
    { name: "About", path: "/about" },
    { name: "Work", path: "/projects" },
    { name: "Blogs", path: "/blog" },
];

export function Navbar() {
    const [isCommandOpen, setIsCommandOpen] = useState(false);
    const [isScrolled, setIsScrolled] = useState(false);
    const pathname = usePathname();
    const [hoveredPath, setHoveredPath] = useState<string | null>(null);

    useEffect(() => {
        const handleKeyDown = (e: KeyboardEvent) => {
            if ((e.metaKey || e.ctrlKey) && e.key === "k") {
                e.preventDefault();
                setIsCommandOpen((prev) => !prev);
            }
        };

        const handleScroll = () => {
            setIsScrolled(window.scrollY > 100);
        };

        window.addEventListener("keydown", handleKeyDown);
        window.addEventListener("scroll", handleScroll);

        // Initial check
        handleScroll();

        return () => {
            window.removeEventListener("keydown", handleKeyDown);
            window.removeEventListener("scroll", handleScroll);
        }
    }, []);

    return (
        <>
            <motion.header
                initial={{ y: -100, opacity: 0 }}
                animate={{ y: 0, opacity: 1 }}
                transition={{ duration: 0.8, ease: "easeOut" }}
                className="fixed top-0 left-0 right-0 z-50 px-6 py-6 pointer-events-none"
            >
                <div className="max-w-[1400px] mx-auto flex items-center justify-between pointer-events-auto">
                    {/* Left: Logo & Title */}
                    <div className="flex items-center space-x-4">
                        <div className="text-2xl font-serif italic font-bold">PM</div>
                        <div className={`hidden sm:flex flex-col transition-all duration-500 delay-100 ${isScrolled ? 'opacity-0 -translate-y-4 pointer-events-none' : 'opacity-100 translate-y-0'}`}>
                            <span className="text-[10px] tracking-widest font-semibold text-neutral-500 dark:text-neutral-400">CREATIVE ENGINEER</span>
                            <div className="flex items-center space-x-1.5 mt-0.5">
                                <span className="w-1.5 h-1.5 rounded-full bg-green-500 animate-[pulse_2s_ease-in-out_infinite]"></span>
                                <span className="text-[10px] tracking-widest font-semibold text-green-600 dark:text-green-500">BUILDING THE FUTURE</span>
                            </div>
                        </div>
                    </div>

                    {/* Right Elements */}
                    <div className="flex items-center space-x-3 md:space-x-4">
                        {/* Space placeholder to prevent layout jumping when nav becomes fixed */}
                        {isScrolled && (
                            <div className="hidden md:block w-px h-px" />
                        )}

                        {/* Navigation Pill */}
                        <motion.nav
                            layout
                            className={`hidden md:flex items-center px-1.5 py-1.5 rounded-full bg-neutral-100/90 dark:bg-[#111]/90 backdrop-blur-md border border-neutral-200 dark:border-[#222] shadow-sm transition-colors ${isScrolled ? "fixed top-6 left-0 right-0 mx-auto w-max z-[60]" : "relative"
                                }`}
                        >
                            <ul className="flex items-center relative" onMouseLeave={() => setHoveredPath(null)}>
                                {links.map((link) => {
                                    const isActive = pathname === link.path || (link.path !== "/" && pathname.startsWith(link.path));
                                    const showPill = hoveredPath === link.path || (hoveredPath === null && isActive);

                                    return (
                                        <li
                                            key={link.name}
                                            className="relative"
                                            onMouseEnter={() => setHoveredPath(link.path)}
                                        >
                                            <Link
                                                href={link.path}
                                                className={`relative px-5 py-2 text-sm font-medium transition-colors duration-300 rounded-full flex items-center justify-center z-10 ${showPill
                                                    ? "text-white dark:text-[#111]"
                                                    : "text-neutral-600 dark:text-neutral-400 hover:text-black dark:hover:text-white"
                                                    }`}
                                            >
                                                {link.name}
                                            </Link>

                                            {/* Sliding Active Pill Background */}
                                            {showPill && (
                                                <motion.div
                                                    layoutId="nav-pill"
                                                    className="absolute inset-0 bg-[#111] dark:bg-white rounded-full shadow-sm -z-10"
                                                    transition={{ type: "spring", stiffness: 350, damping: 30 }}
                                                />
                                            )}
                                        </li>
                                    );
                                })}
                                <li
                                    className="relative group"
                                    onMouseEnter={() => setHoveredPath('more')}
                                >
                                    <button className={`px-5 py-2 text-sm font-medium transition-all duration-300 rounded-full flex items-center relative z-10 space-x-1 outline-none ${hoveredPath === 'more' ? 'text-white dark:text-[#111]' : 'text-neutral-600 dark:text-neutral-400 hover:text-black dark:hover:text-white'}`}>
                                        <span>More</span>
                                        <svg width="10" height="6" viewBox="0 0 10 6" fill="none" xmlns="http://www.w3.org/2000/svg" className="mt-0.5 opacity-50 transition-transform duration-300 group-hover:rotate-180">
                                            <path d="M1 1L5 5L9 1" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round" />
                                        </svg>
                                    </button>

                                    {/* Sliding Active Pill Background for More button */}
                                    {hoveredPath === 'more' && (
                                        <motion.div
                                            layoutId="nav-pill"
                                            className="absolute inset-0 bg-[#111] dark:bg-white rounded-full shadow-sm -z-10"
                                            transition={{ type: "spring", stiffness: 350, damping: 30 }}
                                        />
                                    )}

                                    {/* Dropdown Menu */}
                                    <div className="absolute top-full left-1/2 -translate-x-1/2 pt-4 opacity-0 invisible group-hover:opacity-100 group-hover:visible transition-all duration-200 w-48 z-50">
                                        <div className="bg-white dark:bg-[#111] border border-neutral-200 dark:border-[#333] rounded-2xl shadow-xl overflow-hidden p-2 flex flex-col items-start transform origin-top scale-95 group-hover:scale-100 transition-transform duration-200">
                                            <Link
                                                href="/contact"
                                                className="w-full text-left px-4 py-2 text-sm font-medium text-neutral-600 dark:text-neutral-400 hover:text-black dark:hover:text-white hover:bg-neutral-100 dark:hover:bg-[#222] rounded-xl transition-colors mb-1"
                                            >
                                                Contact Me
                                            </Link>

                                            <div className="w-full h-px bg-neutral-200 dark:bg-[#333] my-1" />

                                            <div className="w-full px-4 py-2">
                                                <p className="text-[10px] font-bold tracking-wider text-neutral-400 dark:text-neutral-500 uppercase mb-2">
                                                    Links
                                                </p>
                                                <div className="flex flex-col space-y-1 -mx-2">
                                                    <a
                                                        href="https://linkedin.com/in/peshalmishra"
                                                        target="_blank"
                                                        rel="noopener noreferrer"
                                                        className="w-full text-left px-2 py-1.5 text-sm font-medium text-neutral-600 dark:text-neutral-400 hover:text-black dark:hover:text-white hover:bg-neutral-100 dark:hover:bg-[#222] rounded-lg transition-colors flex items-center justify-between group/link"
                                                    >
                                                        LinkedIn
                                                        <svg className="w-3 h-3 opacity-0 -translate-x-2 group-hover/link:opacity-100 group-hover/link:translate-x-0 transition-all" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M5 12h14M12 5l7 7-7 7" /></svg>
                                                    </a>
                                                    <a
                                                        href="https://github.com/peshalmishra"
                                                        target="_blank"
                                                        rel="noopener noreferrer"
                                                        className="w-full text-left px-2 py-1.5 text-sm font-medium text-neutral-600 dark:text-neutral-400 hover:text-black dark:hover:text-white hover:bg-neutral-100 dark:hover:bg-[#222] rounded-lg transition-colors flex items-center justify-between group/link"
                                                    >
                                                        GitHub
                                                        <svg className="w-3 h-3 opacity-0 -translate-x-2 group-hover/link:opacity-100 group-hover/link:translate-x-0 transition-all" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M5 12h14M12 5l7 7-7 7" /></svg>
                                                    </a>
                                                    <a
                                                        href="https://twitter.com/peshalmishra"
                                                        target="_blank"
                                                        rel="noopener noreferrer"
                                                        className="w-full text-left px-2 py-1.5 text-sm font-medium text-neutral-600 dark:text-neutral-400 hover:text-black dark:hover:text-white hover:bg-neutral-100 dark:hover:bg-[#222] rounded-lg transition-colors flex items-center justify-between group/link"
                                                    >
                                                        Twitter
                                                        <svg className="w-3 h-3 opacity-0 -translate-x-2 group-hover/link:opacity-100 group-hover/link:translate-x-0 transition-all" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M5 12h14M12 5l7 7-7 7" /></svg>
                                                    </a>
                                                </div>
                                            </div>
                                        </div>
                                    </div>
                                </li>
                            </ul>
                        </motion.nav>

                        {/* Theme Toggle Button Wrapper*/}
                        <div className="w-10 h-10 rounded-full border border-neutral-200 dark:border-[#333] flex items-center justify-center bg-white dark:bg-[#111] shadow-sm hidden sm:flex">
                            <ThemeToggle />
                        </div>

                        {/* Book a Call */}
                        <Link
                            href="/contact"
                            className="hidden sm:flex px-5 py-2.5 text-sm font-medium text-white bg-[#111] dark:text-[#111] dark:bg-[#ededed] rounded-full hover:bg-black dark:hover:bg-white transition-colors shadow-sm whitespace-nowrap"
                        >
                            Book a Call
                        </Link>

                        {/* Command Icon */}
                        <button
                            onClick={() => setIsCommandOpen(true)}
                            aria-label="Command Menu"
                            className="w-10 h-10 rounded-full border border-neutral-200 dark:border-[#333] flex items-center justify-center text-neutral-600 dark:text-neutral-400 hover:text-black dark:hover:text-white hover:bg-neutral-100 dark:hover:bg-[#222] transition-colors shadow-sm bg-white dark:bg-[#111]"
                        >
                            <Command className="w-4 h-4" />
                        </button>
                    </div>
                </div>
            </motion.header >

            <CommandMenu isOpen={isCommandOpen} onClose={() => setIsCommandOpen(false)} />
        </>
    );
}
